// poliub-frontend/src/RoutesApp.js
import React from "react";
import { BrowserRouter, Routes, Route, Navigate } from "react-router-dom";
import { useAuth } from "./context/AuthContext";

// Importe aqui seus componentes de página:
import LoginPage from "./pages/LoginPage";          // ex: tela de login
import DashboardAluno from "./pages/DashboardAluno"; // ex: dashboard para aluno
import DashboardRecepcao from "./pages/DashboardRecepcao"; // ex: dashboard para recepção
import ListaPeriodos from "./components/ListaPeriodos";    // exemplo de uso
import ListaDisciplinas from "./components/ListaDisciplinas";
import ListaPacientes from "./components/ListaPacientes";
import ListaAlunos from "./components/ListaAlunos";
import FormAgendamento from "./components/FormAgendamento";
import ListaAgendamentos from "./components/ListaAgendamentos";

/**
 * ProtectedRoute: se não estiver logado (user == null), redireciona para /login
 */
function ProtectedRoute({ children }) {
  const { user } = useAuth();
  if (!user) {
    return <Navigate to="/login" replace />;
  }
  return children;
}

export default function RoutesApp() {
  return (
    <BrowserRouter>
      <Routes>
        {/* Rota de login (pública) */}
        <Route path="/login" element={<LoginPage />} />

        {/* A partir daqui, só entra se estiver logado */}
        <Route
          path="/"
          element={
            <ProtectedRoute>
              <DashboardRecepcao />
            </ProtectedRoute>
          }
        >
          {/* Exemplo de subrotas dentro do dashboard */}
          <Route
            path="aluno"
            element={
              <ProtectedRoute>
                <DashboardAluno />
              </ProtectedRoute>
            }
          />
          <Route
            path="periodos"
            element={
              <ProtectedRoute>
                <ListaPeriodos />
              </ProtectedRoute>
            }
          />
          <Route
            path="disciplinas"
            element={
              <ProtectedRoute>
                <ListaDisciplinas />
              </ProtectedRoute>
            }
          />
          <Route
            path="pacientes"
            element={
              <ProtectedRoute>
                <ListaPacientes />
              </ProtectedRoute>
            }
          />
          <Route
            path="alunos"
            element={
              <ProtectedRoute>
                <ListaAlunos />
              </ProtectedRoute>
            }
          />
          <Route
            path="agendamentos"
            element={
              <ProtectedRoute>
                <ListaAgendamentos />
              </ProtectedRoute>
            }
          />
          <Route
            path="agendar"
            element={
              <ProtectedRoute>
                <FormAgendamento />
              </ProtectedRoute>
            }
          />
          {/* Adicione aqui quantas rotas internas você precisar */}
        </Route>

        {/* Qualquer rota não reconhecida redireciona para /login ou dashboard */}
        <Route path="*" element={<Navigate to="/login" replace />} />
      </Routes>
    </BrowserRouter>
  );
}
